  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const { paymentIntentId, clientSecret, cardDetails } = await req.json();

    console.log('Confirming payment for intent:', paymentIntentId);

    // Validate input
