-- Add fields to track renewal reminders
ALTER TABLE payments
ADD COLUMN IF NOT EXISTS purchase_date TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
ADD COLUMN IF NOT EXISTS renewal_reminder_sent BOOLEAN DEFAULT FALSE,
ADD COLUMN IF NOT EXISTS renewal_reminder_sent_at TIMESTAMP WITH TIME ZONE,
ADD COLUMN IF NOT EXISTS subscription_end_date TIMESTAMP WITH TIME ZONE;

-- Create index for efficient querying of payments needing renewal reminders
CREATE INDEX IF NOT EXISTS idx_payments_renewal_reminder 
ON payments(subscription_end_date, renewal_reminder_sent) 
WHERE renewal_reminder_sent = FALSE;

-- Update existing records to set subscription_end_date (365 days from created_at)
UPDATE payments 
SET subscription_end_date = created_at + INTERVAL '365 days',
    purchase_date = created_at
WHERE subscription_end_date IS NULL;

-- Create a function to automatically set subscription_end_date on insert
CREATE OR REPLACE FUNCTION set_subscription_end_date()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.subscription_end_date IS NULL THEN
    NEW.subscription_end_date := NEW.created_at + INTERVAL '365 days';
  END IF;
  IF NEW.purchase_date IS NULL THEN
    NEW.purchase_date := NEW.created_at;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger to automatically set subscription_end_date
DROP TRIGGER IF EXISTS trigger_set_subscription_end_date ON payments;
CREATE TRIGGER trigger_set_subscription_end_date
  BEFORE INSERT ON payments
  FOR EACH ROW
  EXECUTE FUNCTION set_subscription_end_date();

