Deno.serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    // Get current date and date 12 months ago (for testing, we'll check for subscriptions ending in 7 days)
    const now = new Date();
    const reminderDate = new Date(now);
    reminderDate.setDate(reminderDate.getDate() + 7); // Send reminder 7 days before expiry

    console.log('Checking for subscriptions ending around:', reminderDate.toISOString());

    // Find payments that need renewal reminders
    // (subscription ends in ~7 days and reminder not yet sent)
    const { data: payments, error: fetchError } = await supabaseClient
      .from('payments')
      .select('*')
      .eq('status', 'succeeded')
      .eq('renewal_reminder_sent', false)
      .gte('subscription_end_date', now.toISOString())
      .lte('subscription_end_date', reminderDate.toISOString());

    if (fetchError) {
      console.error('Error fetching payments:', fetchError);
      return new Response(JSON.stringify({
        success: false,
        error: fetchError.message
      }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 400
      });
    }

    console.log(`Found ${payments?.length || 0} payments needing renewal reminders`);

    if (!payments || payments.length === 0) {
      return new Response(JSON.stringify({
        success: true,
        message: 'No renewal reminders to send',
        count: 0
      }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200
      });
    }

    const results = [];

    // Send renewal reminders for each payment
    for (const payment of payments as Payment[]) {
      console.log(`Processing payment ${payment.id}`);

      const recipients = payment.recipients || [];

      for (const recipient of recipients) {
        const emailResult = await sendEmail(
          recipient.email,
          '🌟 Your Daily Whispers Subscription is Ending Soon',
          generateRenewalEmailHTML(
            recipient.name,
            payment.option_name,
            payment.subscription_end_date
          )
        );

        results.push({
          paymentId: payment.id,
          recipientEmail: recipient.email,
          success: emailResult.success,
          error: emailResult.error
        });

        console.log(`Email sent to ${recipient.email}:`, emailResult.success);
      }

      // Mark reminder as sent
      const { error: updateError } = await supabaseClient
        .from('payments')
        .update({
          renewal_reminder_sent: true,
          renewal_reminder_sent_at: now.toISOString()
        })
        .eq('id', payment.id);

      if (updateError) {
        console.error(`Error updating payment ${payment.id}:`, updateError);
      }
    }

    const successCount = results.filter(r => r.success).length;
    const failureCount = results.filter(r => !r.success).length;

    return new Response(JSON.stringify({
      success: true,
      message: `Sent ${successCount} renewal reminders, ${failureCount} failed`,
      totalProcessed: payments.length,
      successCount,
      failureCount,
      results
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200
    });
  } catch (error) {
    console.error('Error processing renewal reminders:', error);
    return new Response(JSON.stringify({
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error'
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 500
    });
  }
});

import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type'
};

/**
 * This Edge Function is designed to be called by a cron job (e.g., GitHub Actions, external scheduler)
 * It checks for payments that need renewal reminders and triggers the send-renewal-reminder function
 * 
 * To set up a cron job:
 * 1. Use GitHub Actions with a scheduled workflow
 * 2. Use an external service like cron-job.org or EasyCron
 * 3. Call this endpoint daily: https://[your-project-ref].supabase.co/functions/v1/check-renewal-reminders-cron
 * 
 * Example GitHub Actions workflow (.github/workflows/renewal-reminders.yml):
 * 
 * name: Send Renewal Reminders
 * on:
 *   schedule:
 *     - cron: '0 9 * * *'  # Run daily at 9 AM UTC
 *   workflow_dispatch:  # Allow manual trigger
 * 
 * jobs:
 *   send-reminders:
 *     runs-on: ubuntu-latest
 *     steps:
 *       - name: Trigger Renewal Reminders
 *         run: |
 *           curl -X POST \
 *             -H "Authorization: Bearer ${{ secrets.SUPABASE_SERVICE_ROLE_KEY }}" \
 *             https://[your-project-ref].supabase.co/functions/v1/check-renewal-reminders-cron
 */

Deno.serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    console.log('Cron job triggered: Checking for renewal reminders');

    // Verify authorization (optional but recommended for cron jobs)
    const authHeader = req.headers.get('Authorization');
    const cronSecret = Deno.env.get('CRON_SECRET');

    if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
      console.error('Unauthorized cron job attempt');
      return new Response(JSON.stringify({
        success: false,
        error: 'Unauthorized'
      }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 401
      });
    }

    // Call the send-renewal-reminder function
    const supabaseUrl = Deno.env.get('SUPABASE_URL');
    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

    if (!supabaseUrl || !serviceRoleKey) {
      throw new Error('Supabase configuration missing');
    }

    const response = await fetch(`${supabaseUrl}/functions/v1/send-renewal-reminder`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${serviceRoleKey}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      const error = await response.text();
      console.error('Error calling send-renewal-reminder:', error);
      return new Response(JSON.stringify({
        success: false,
        error: `Failed to send renewal reminders: ${error}`
      }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 500
      });
    }

    const result = await response.json();
    console.log('Renewal reminders processed:', result);

    return new Response(JSON.stringify({
      success: true,
      message: 'Renewal reminders check completed',
      result
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200
    });
  } catch (error) {
    console.error('Error in cron job:', error);
    return new Response(JSON.stringify({
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error'
    }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 500
    });
  }
});
